UPDATE books SET description_kk = 'Ұлы қазақ ақынының философиялық-дидактикалық эсселері. Өмір мәні, имандылық пен ағартушылық туралы 45 қара сөзден тұратын жинақ. Бұл шығарма дәуірдің тарихи және мәдени контекстін тереңірек түсінуге көмектеседі, сондай-ақ автордың негізгі идеяларын жарқын образдар мен мағыналық егжей-тегжейлер арқылы ашады. Кітап тақырыппен алғаш танысуға да, ой сала қайта оқу мен талқылауға да қолайлы.' WHERE id = '33333333-0000-0000-0000-000000000001';
