UPDATE events SET title_kk = 'Абай оқулары', description_kk = 'Абай Құнанбайұлының поэзиясына арналған жыл сайынғы оқулар. Оқырмандардың сахнадағы өнері, домбырашылардың музыкалық сүйемелдеуі, ұлы ақынның философиялық идеяларын талқылау.' WHERE id = '77777777-0000-0000-0000-000000000001';
UPDATE events SET title_kk = 'Кітап клубы: Шебер және Маргарита', description_kk = 'Михаил Булгаковтың романын талқылау. Шығарманың символикасын, тарихи контекстін, жақсылық пен жамандық туралы мәңгілік тақырыптарын талдаймыз.' WHERE id = '77777777-0000-0000-0000-000000000002';
UPDATE events SET title_kk = 'Дәріс: ХХ ғасырдағы қазақ әдебиеті', description_kk = 'Кеңес дәуіріндегі қазақ әдебиетінің негізгі шығармалары мен авторларына шолу. Әуезов, Есенберлин, Мүсірепов — олардың тағдыры мен шығармашылығы.' WHERE id = '77777777-0000-0000-0000-000000000003';
UPDATE events SET title_kk = 'Балалар оқу марафоны', description_kk = '7–12 жас аралығындағы балаларға арналған оқу марафоны. Кітаптар бойынша байқаулар, викториналар, қатысушыларға сыйлықтар мен дипломдар.' WHERE id = '77777777-0000-0000-0000-000000000004';
UPDATE events SET title_kk = 'Заманауи қазақ жазушыларымен кездесу', description_kk = 'Заманауи қазақ прозасы мен поэзиясы авторларымен тікелей кездесу. Автограф беру, жаңа кітаптарды талқылау, шығармашылық кеш.' WHERE id = '77777777-0000-0000-0000-000000000005';
UPDATE events SET title_kk = 'Әлемдік фантастика: Верннен Азимовқа дейін', description_kk = 'Ғылыми фантастиканың классиктері туралы дәріс. Жанрдың тарихы, негізгі шығармалары, ғылым мен технологияға әсері.' WHERE id = '77777777-0000-0000-0000-000000000006';
UPDATE events SET title_kk = 'Поэзия кеші: Күміс ғасыр', description_kk = 'Пушкин, Тютчев, Блок, Ахматова өлеңдерін оқу. Музыкалық сүйемелдеу, әдеби салонның тірі атмосферасы.' WHERE id = '77777777-0000-0000-0000-000000000007';
UPDATE events SET title_kk = 'Шеберлік сабағы: Кітапқа пікір жазу', description_kk = 'Мектеп оқушылары мен студенттерге арналған практикалық шеберлік сабағы. Кітапты талдауға, ойды құрылымдауға және оқу әсерін сауатты жеткізуге үйренеміз.' WHERE id = '77777777-0000-0000-0000-000000000008';
UPDATE events SET title_kk = 'Алматы кітап жәрмеңкесі', description_kk = 'Жыл сайынғы кітап жәрмеңкесі. 50-ден астам баспа, жаңа басылымдардың тұсаукесері, жеңілдіктер, авторлармен кездесулер. Кіру тегін.' WHERE id = '77777777-0000-0000-0000-000000000009';
UPDATE events SET title_kk = 'Философиялық клуб: Камю және абсурд', description_kk = 'Альбер Камюдің философиясын талдаймыз — Бөтен, Сизиф туралы аңыз, Оба. Абсурд дегеніміз не және онымен қалай өмір сүруге болады.' WHERE id = '77777777-0000-0000-0000-000000000010';
